import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse(`{"title":"Ben's Bites — 2026-05-24","description":"","frontmatter":{"title":"Ben's Bites — 2026-05-24","date":"2026-05-24T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-24-bens-bites.md","filePath":"research/ai-news/2026-05/2026-05-24-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-05/2026-05-24-bens-bites.md"};function s(i,e,l,h,p,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-05-24" tabindex="-1">🍔 Ben&#39;s Bites — 2026-05-24 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-05-24" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-05-24&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="google-s-take-on-openclaw" tabindex="-1"><a href="https://www.bensbites.com/p/googles-take-on-openclaw" target="_blank" rel="noreferrer">Google&#39;s take on openclaw</a> <a class="header-anchor" href="#google-s-take-on-openclaw" aria-label="Permalink to &quot;[Google&#39;s take on openclaw](https://www.bensbites.com/p/googles-take-on-openclaw)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-21</em></p><p>Hey folks,</p><p>My first fund is now at 5x! I had a very notable firm not invest in my latest fund as they were assessing if I was a 5x fund returner… seems like I am. Fund 2 is also at ~3x with 55% IRR. Fund 3 I&#39;m starting to fundraise for again, looking for operators, $100k minimum. Deployed 4 cheques so far. I invest in developer tools and infrastructure - essentially anything for an agent-first world. If you or anyone you know would be interested, please let me know.</p><p>Google&#39;s I/O event on Tuesday was overshadowed by <a href="https://x.com/karpathy/status/2056753169888334312" target="_blank" rel="noreferrer">Andrej Karpathy joining Antrhopic&#39;s pre-training team</a> under Nick Joseph to build and lead a new group focused on using Claude to accelerate pre-training research. Using Claude to help pre-train Claude models.</p><p>And now they have the compute… SpaceX&#39;s IPO filing discloses Anthropic will pay $1.25 billion monthly for compute.</p><p>Just as Anthropic project $10.9 billion June quarter revenue and its first operating profit. Which could well lead them to a valuation higher than OpenAI. Who have been reported are potentially filing for an IPO imminently (some sources say as early as tomorrow) - but nothing official or confirmed.</p><hr><p><em>Ben &#39;s Bites is brought to you by <a href="https://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Attio, the AI CRM</a></em></p><blockquote><p>GTM Atlas is the map for modern go-to-market. Written by top operators, Atlas is a free resource covering the full customer journey, with systems thinking that scales with you. Curated by Attio. Mapped by operators. <a href="http://atlas.attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter&amp;utm_campaign=bens_bites-Y26&amp;utm_content=atlas" target="_blank" rel="noreferrer">Read now</a></p></blockquote><hr><h4 id="headlines" tabindex="-1">Headlines <a class="header-anchor" href="#headlines" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p>Google I/O wasn&#39;t all that interesting.</p><ul><li><p>They have a new model family aiming for any input/any output. <strong><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-omni/" target="_blank" rel="noreferrer">Gemini Omni Flash</a></strong> - the first model in that family generates and edits videos. The technical difference between Omni and Veo is similar to that between Imagen and Nano Banana.</p></li><li><p>For general model upgrades, they only released <strong><a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-5/" target="_blank" rel="noreferrer">Gemini 3.5 Flash</a>,</strong> which, on paper, is better than 3.1 Pro. This model is fast and intelligent, but not cheap anymore. It also has the knowledge cutoff of Jan 2025, so it does not know about vibe coding and beyond. 3.5 Pro is coming next month, but I don&#39;t have high hopes.</p></li><li><p><strong><a href="https://blog.google/innovation-and-ai/technology/developers-tools/google-io-2026-developer-highlights/" target="_blank" rel="noreferrer">Antigravity</a></strong> is now a clone of Codex, Conductor and every other AI coding agent app. It&#39;s usable -- but I couldn&#39;t find a way to bypass permission quickly. They have also made installing the IDE optional.</p></li><li><p>Their answer to OpenClaw is called <strong><a href="https://blog.google/innovation-and-ai/products/gemini-app/next-evolution-gemini-app/" target="_blank" rel="noreferrer">Gemini Spark</a></strong> , a 24/7 personal agent that works across Workspace, but it&#39;s &quot;coming soon&quot;, so no idea how well it works.</p></li></ul></li><li><p>OpenAI says one of its models <strong><a href="https://openai.com/index/model-disproves-discrete-geometry-conjecture/" target="_blank" rel="noreferrer">solved a famous math problem</a>,</strong> and external mathematicians checked the proof. They also added a <strong><a href="https://openai.com/index/advancing-content-provenance/" target="_blank" rel="noreferrer">public image verifier</a></strong> for images made with ChatGPT, the API and Codex. It checks C2PA metadata and also SynthID (from Google). <a href="https://openai.com/verify/" target="_blank" rel="noreferrer">Try it here</a>.</p></li><li><p><strong><a href="https://www.figma.com/blog/the-figma-agent-is-here/" target="_blank" rel="noreferrer">Figma has a design agent inside the canvas</a></strong>. It can start from a design layer, generate multiple directions in parallel, make bulk edits, use your design system, and work in the same file as your team.</p></li><li><p>Now any product developer can ship globally: <strong>Neimo MCP</strong> turns Claude, OpenAI&#39;s Codex, and Manus into regulatory experts across 200+ jurisdictions. Built by <a href="https://gamesbeat.com/k-id-launches-ai-powered-compliance-tool-aimed-at-speeding-global-game-launches-exclusive/" target="_blank" rel="noreferrer">the team</a> behind compliance for some of the world&#39;s largest games and platforms. <a href="https://k-id.com/neimo-mcp?utm_source=bensbites&amp;utm_medium=newsletter&amp;utm_campaign=44143235-Neimo-MCP-Launch&amp;utm_content=text_cta" target="_blank" rel="noreferrer">Try Neimo free 👉</a>*</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed" tabindex="-1">My feed <a class="header-anchor" href="#my-feed" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p><a href="https://handinger.com" target="_blank" rel="noreferrer">Handinger</a>: Build AI agents in plain English, connect them to your tools, and kill the boring admin work nobody wants.*</p></li><li><p><a href="https://x.com/FactoryAI/status/2057178459911467162" target="_blank" rel="noreferrer">Factory&#39;s Deferred Context Engine</a> - Droid now loads tools more selectively to cut context size by 40%.</p></li><li><p><a href="https://x.com/jxnlco/status/2057153744630890620" target="_blank" rel="noreferrer">Getting the most out of Codex</a>.</p></li><li><p><a href="https://x.com/nbaschez/status/2057139892883464243" target="_blank" rel="noreferrer">Roughdraft</a> - local open-source interface for commenting and suggested changes on markdown docs/plans.</p></li><li><p><a href="https://x.com/pierrecomputer/status/2057174934674124941" target="_blank" rel="noreferrer">DiffsHub</a> - replace <em>github</em> with <em>diffshub</em> in a public GitHub diff URL to virtualise and inspect huge diffs quickly.</p></li><li><p><a href="https://x.com/astuyve/status/2056772052636319955" target="_blank" rel="noreferrer">Lapdog</a> from Datadog - local tracing for reasoning and tool calls in Codex, Claude Code and Pi.</p></li><li><p><a href="https://x.com/meetgranola/status/2057100483219857868" target="_blank" rel="noreferrer">Granola Briefs</a> - searches your email, web and previous meeting notes before a meeting, then gives you three bullets.</p></li><li><p><a href="https://buildwithtaste.com/product/mcp" target="_blank" rel="noreferrer">Taste MCP</a> - what if your design preferences could follow you into Codex, Cursor, Claude Code?</p></li><li><p><a href="https://openai.com/business/guaranteed-capacity/" target="_blank" rel="noreferrer">OpenAI Guaranteed Capacity</a> - companies can pre-book OpenAI compute for 1-3 years, so important products and agents don&#39;t get throttled when demand spikes.</p></li><li><p><a href="https://x.com/p0/status/2056752047031279726" target="_blank" rel="noreferrer">Parallel Web Systems Index</a> - lets publishers see which agents are reading their content and get paid. First partners include The Atlantic, Fortune, Every and Packy.</p></li><li><p><a href="https://x.com/yoheinakajima/status/2057099245430222926" target="_blank" rel="noreferrer">Active Graph</a> - open-source framework for long-running agents to remember what happened, react to new events, and compare different agent runs.</p></li><li><p>Making <a href="https://x.com/ClaudeDevs/status/2056835339193561170" target="_blank" rel="noreferrer">computer use</a> reliable in production.</p></li><li><p>A poisoned third-party VS Code extension compromised a GitHub employee&#39;s device, and <a href="https://github.blog/security/investigating-unauthorized-access-to-githubs-internal-repositories/" target="_blank" rel="noreferrer">~3,800 internal GitHub repos were exfiltrated</a>.</p></li><li><p><a href="https://cohere.com/blog/command-a-plus" target="_blank" rel="noreferrer">Cohere released Command A+</a> - an open-source enterprise model. supports text/image/tool use and runs on two H100s/one B200 with quantisation.</p></li></ul><hr><h4 id="afters" tabindex="-1">Afters <a class="header-anchor" href="#afters" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr><h2 id="can-i-get-my-agents-on-the-phone" tabindex="-1"><a href="https://www.bensbites.com/p/can-i-get-my-agents-on-the-phone" target="_blank" rel="noreferrer">Can I get my agents on the phone?</a> <a class="header-anchor" href="#can-i-get-my-agents-on-the-phone" aria-label="Permalink to &quot;[Can I get my agents on the phone?](https://www.bensbites.com/p/can-i-get-my-agents-on-the-phone)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-05-19</em></p><p>Hey folks</p><p><a href="https://blog.google/innovation-and-ai/technology/developers-tools/io-2026-save-the-date/" target="_blank" rel="noreferrer">Google I/O starts today</a>, and Logan tweeted: &quot;<a href="https://x.com/OfficialLoganK/status/2056107524802457887" target="_blank" rel="noreferrer">The model is the product</a>&quot;. There have been some rumours that the latest Gemini model scores similar on benchmarks to GPT 5.5 - but we&#39;ll see how it feels when actually using it - previous models also scored well but didn&#39;t feel great to work with.</p><p>When models are so good, harnesses will be much less important. I just don&#39;t think today is the day that happens. And on that point, the role of a harness will probably just shift - instead of managing how/which tools to use, the system prompt, context management etc it could be managed agents, sandboxing, cloud/local management.</p><p>I started using Codex on my phone…but not all that much to be honest. A lot of the agent harnesses these days have ways to control your sessions from your phone - Claude Code has /remote-control, Pi can build one for itself (i use a telegram one) and Droid has mobile web + Droid computers.</p><p>Most of my mobile first work at the moment is more brainstorming than building and I find myself flitting between all these options all the time.</p><p>I used to use my OpenClaw bot like an addict, but haven&#39;t spoken to the poor bastard for weeks now.</p><p>It may help that I&#39;m currently focused on just one (ish) main thing - this &#39;course&#39;. Which is really more of a library or reference manual on how I think about agents, how I steer them and build with them.</p><hr><p><em>Ben &#39;s Bites is brought to you by <strong><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent from Airtable</a></strong></em></p><blockquote><p><em><a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Hyperagent</a>, the cloud agent system with full computing environments, is giving $10M in inference credits to help founders build and run agent-first companies. The first 500 qualifying applicants gain access to this limited founder offer. <a href="https://hyperagent.com/founding500?utm_source=newsletter&amp;utm_medium=paidmedia&amp;utm_campaign=HA-BENSBITES" target="_blank" rel="noreferrer">Applications close May 31st</a>.</em></p></blockquote><hr><h4 id="headlines-1" tabindex="-1">Headlines <a class="header-anchor" href="#headlines-1" aria-label="Permalink to &quot;Headlines&quot;">​</a></h4><ul><li><p><strong><a href="https://openai.com/index/work-with-codex-from-anywhere/" target="_blank" rel="noreferrer">Codex now connects your Mac to your phone</a></strong>. You can start tasks in Codex from your phone, but the actual work still runs on your Mac, devbox or remote machine, i.e. files, setup and credentials stay where they are, while you can approve commands, answer questions, and review diffs from your phone. This update also brings Hooks to Codex.</p></li><li><p>Anthropic is <strong><a href="https://x.com/AnthropicAI/status/2056419620643541012" target="_blank" rel="noreferrer">acquiring Stainless</a></strong> , a platform to build SDKs (also used by OpenAI), and they are shutting the service down. Also, at their London conference, they added self-hosted sandboxes and MCP tunnels to <strong><a href="https://x.com/claudeai/status/2056645485696315581" target="_blank" rel="noreferrer">Claude Managed Agents</a></strong> - their &quot;running agents made easy&quot; product for companies.</p></li><li><p><strong><a href="https://blog.cloudflare.com/cyber-frontier-models/" target="_blank" rel="noreferrer">Cloudflare tested Anthropic&#39;s Mythos</a></strong> against 50 of its repos. Quick takeaways:</p><ul><li><p>Mythos is great at spotting real attacks, which are often many small vulnerabilities connected in a chain.</p></li><li><p>A single model, however smart, without a good harness leaves a lot to be found.</p></li><li><p>&quot;Find bugs fast and patch them faster&quot; is not a good idea. Teams need to focus on making bugs harder to chain (even if they exist) and to exploit.</p></li></ul></li><li><p><strong><a href="https://cursor.com/blog/composer-2-5" target="_blank" rel="noreferrer">Cursor&#39;s Composer 2.5</a></strong> (partly trained on SpaceX&#39;s GPUs) is out. The selective benchmarks that Cursor reports put the model roughly at the same place as Opus 4.7-xhigh and GPT-5.5-high, while being much cheaper than them.</p></li></ul><hr><p><a href="https://www.bensbites.com/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><h4 id="my-feed-1" tabindex="-1">My feed <a class="header-anchor" href="#my-feed-1" aria-label="Permalink to &quot;My feed&quot;">​</a></h4><ul><li><p>Two AI startups worth watching: <a href="https://x.com/skirano/status/2054975534539370708" target="_blank" rel="noreferrer">Magicpath (design canvas)</a> and <a href="https://www.raindrop.ai/workshop/" target="_blank" rel="noreferrer">Raindrop AI (monitoring agents in production)</a>, both of which are making their products usable by external coding agents like Claude Code or Codex.</p></li><li><p><a href="https://x.ai/cli" target="_blank" rel="noreferrer">Even Grok/xAI has a coding CLI now</a>. Let&#39;s see what Google does with Gemini CLI at I/O today.</p></li><li><p><a href="https://x.com/karrisaarinen/status/2054993293210259752" target="_blank" rel="noreferrer">Linear Agent</a> can now read the codebase directly to build a hypothesis, investigate support questions, find people who worked on a feature, and more.</p></li><li><p>Best practices for <a href="https://claude.com/blog/how-claude-code-works-in-large-codebases-best-practices-and-where-to-start" target="_blank" rel="noreferrer">running Claude Code at scale</a>.</p></li><li><p>Citadel&#39;s founder, Ken Griffin, one of the anti-AI hype people, is now saying that they are seeing <a href="https://youtu.be/Csjy_A3Kj9s?t=1319" target="_blank" rel="noreferrer">high-skilled jobs being &quot;automated&quot; by AI.</a></p></li><li><p><a href="https://browse.sh/" target="_blank" rel="noreferrer">Browse.sh</a> from Browserbase - open-source catalogue of skills/playbooks for agents to perform tasks on the internet.</p></li><li><p><a href="https://github.com/firstbatchxyz/watchmen" target="_blank" rel="noreferrer">Watchmen</a> - skill files your coding agents should already have from your past sessions. Local and open-source.</p></li><li><p><a href="https://x.com/cognition/status/2056396941181727210" target="_blank" rel="noreferrer">Devin Auto-Triage</a> monitors bugs, alerts and incidents, investigates them and comes back with context, next steps or a PR.</p></li><li><p><a href="https://x.com/JiaZhihao/status/2055327218415341978" target="_blank" rel="noreferrer">Motus Tracing</a> - open-source observability for AI agents.</p></li><li><p><a href="https://x.com/nozmen/status/2056396698688122910" target="_blank" rel="noreferrer">designmd.sh</a> - a public registry for DESIGN.md files, so agents can understand design systems from repos.</p></li><li><p><a href="https://jxnl.github.io/blog/writing/2026/05/10/codex-maxxing/" target="_blank" rel="noreferrer">Jason Liu on Codex maxxing</a> - daily primitives for durable threads, shared memory, and keeping Codex useful across a real workflow.</p></li><li><p><a href="https://buildwithtaste.com/product/mcp" target="_blank" rel="noreferrer">Taste MCP beta</a> - portable design preferences for Codex, Cursor, Claude Code, etc.</p></li><li><p>Claire Vo and Thariq on &quot;<a href="https://youtu.be/Qrpm7E80wQ0" target="_blank" rel="noreferrer">HTML is the new markdown</a>&quot; - using HTML artifacts as specs, micro-UIs, and human-readable agent context.</p></li><li><p><a href="https://x.com/brian_lovin/status/2056444390940516409" target="_blank" rel="noreferrer">Brian Lovin&#39;s Notion Worker</a> - syncs the people you follow on X into a Notion DB with optional AI enrichment.</p></li><li><p>Benedict Evans&#39; new &quot;<a href="https://www.ben-evans.com/presentations" target="_blank" rel="noreferrer">AI Is Eating The World</a>&quot; deck.</p></li><li><p>Coatue says its AI framework moved from &quot;follow the GPU&quot; to &quot;<a href="https://x.com/coatuemgmt/status/2055408437782290480" target="_blank" rel="noreferrer">follow the gigawatt</a>&quot;.</p></li></ul><hr><h4 id="afters-1" tabindex="-1">Afters <a class="header-anchor" href="#afters-1" aria-label="Permalink to &quot;Afters&quot;">​</a></h4><p><a href="https://www.bensbites.com/?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share Ben&#39;s Bites</a></p><hr><ul><li><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p></li><li><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben&#39;s Bites</p></li><li><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p></li></ul><blockquote><h6 id="sponsors-who-make-this-newsletter-possible-1" tabindex="-1"><em>* sponsors who make this newsletter possible 😃</em> <a class="header-anchor" href="#sponsors-who-make-this-newsletter-possible-1" aria-label="Permalink to &quot;_* sponsors who make this newsletter possible :)_&quot;">​</a></h6><h6 id="wanna-partner-with-us-for-the-next-quarter-1" tabindex="-1"><em>Wanna partner with us for the next quarter?</em> <a class="header-anchor" href="#wanna-partner-with-us-for-the-next-quarter-1" aria-label="Permalink to &quot;_Wanna partner with us for the next quarter?_&quot;">​</a></h6><h6 id="email-us-atshanice-bensbites-com-or-k-bensbites-com-1" tabindex="-1"><em>Email us at<a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></em> <a class="header-anchor" href="#email-us-atshanice-bensbites-com-or-k-bensbites-com-1" aria-label="Permalink to &quot;_Email us at[shanice@bensbites.com](mailto:shanice@bensbites.com) or [k@bensbites.com](mailto:k@bensbites.com)_&quot;">​</a></h6></blockquote><p>Ben&#39;s Bites is a reader-supported publication. To receive new posts and support my work, consider becoming a free or paid subscriber.</p><hr>',57)])])}const d=t(n,[["render",s]]);export{c as __pageData,d as default};
